import re
import math
import datetime
import calendar

def transform(row):
    x = row[0]

    # Check if the input is a number
    if alnum(x):
        return x

    # Check if the input is a date
    if re.match(r'\d{4}\s\w+\s\d{1,2}', x):
        return year(x)

    # Check if the input is a number with decimal points
    if digits(x):
        return number_2dp(x)

    # Check if the input is a time
    if re.match(r'\d{1,2}:\d{2}', x):
        return f"{hour(x)}:{minute_2(x)}"

    # Default case
    return x
